parameters.jsCode:
const rawText = $input.item.json.content[0].text;
const tokensUsed = $input.item.json.usage.input_tokens + $input.item.json.usage.output_tokens;

// Strip markdown code fences if Claude wrapped the JSON
const cleaned = rawText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

let posts;
try {
  const parsed = JSON.parse(cleaned);
  posts = parsed.posts || [];
} catch (e) {
  // Fallback: return raw text as single post if JSON parse fails
  posts = [{ id: 1, platform: 'Facebook/Instagram', language: 'ro', text: rawText, hashtags: [] }];
}

return [
  {
    json: {
      posts,
      tokensUsed,
      weekOf: $('Set Hotel Context + Date').item.json.weekOf,
      clientId: $('Set Hotel Context + Date').item.json.clientId,
      generatedAt: new Date().toISOString()
    }
  }
];

const { posts, weekOf, generatedAt } = $input.item.json;

let message = `📱 *Conținut Social Media — Săptămâna ${weekOf}*\n\nAi 3 postări gata de publicat pentru Pensiunea Stejarul.\nCopiază, ajustează dacă dorești, și postează!\n\n`;

posts.forEach((post, index) => {
  const flag = post.language === 'en' ? '🇬🇧' : '🇷🇴';
  const hashtagStr = post.hashtags && post.hashtags.length
    ? '\n' + post.hashtags.map(h => h.startsWith('#') ? h : '#' + h).join(' ')
    : '';
  message += `━━━━━━━━━━━━━━━━━━━━\n`;
  message += `*Postarea ${index + 1}* ${flag} (${post.platform})\n\n`;
  message += post.text;
  message += hashtagStr;
  message += `\n\n`;
});

message += `━━━━━━━━━━━━━━━━━━━━\n_Generat de GuestFlow · ${new Date(generatedAt).toLocaleString('ro-RO', {timeZone: 'Europe/Bucharest'})}_`;

return [{ json: { waMessage: message, posts, weekOf, clientId: $input.item.json.clientId, tokensUsed: $input.item.json.tokensUsed } }];

